    25→export const App = () => {
    26→  const screen = useNavigationStore((state) => state.screen);
    27→  const setScreen = useNavigationStore((state) => state.setScreen);
    28→  const navigateTo = useNavigationStore((state) => state.navigateTo);
    29→  const { data: gitState, isLoading: gitStateLoading } = useGitState();
    30→  const COLORS = useColors();
    31→  const triggerCreatePlan = useAtomSet(createPlanFn, { mode: "promise" });
    32→  const [planningError, setPlanningError] = useState<string | undefined>(undefined);
    33→
    34→  const handlePlanningStart = async () => {
    35→    const plan = usePlanStore.getState().plan;
    36→    console.error("[app] handlePlanningStart, plan._tag:", plan?._tag);
    37→    if (plan?._tag !== "draft") return;
    38→
    39→    try {
    40→      const testPlan = await triggerCreatePlan({
    41→        changesFor: plan.changesFor,
    42→        flowInstruction: plan.instruction,
    43→      });
    44→      console.error("[app] planning succeeded:", testPlan.title, "steps:", testPlan.steps.length);
    45→      usePlanStore.getState().setPlan(Plan.plan(testPlan));
    46→      const { autoRunAfterPlanning, skipPlanning } = usePreferencesStore.getState();
    47→      console.error(
    48→        "[app] autoRunAfterPlanning:",
    49→        autoRunAfterPlanning,
    50→        "skipPlanning:",
    51→        skipPlanning,
    52→      );
    53→      const nextScreen = autoRunAfterPlanning || skipPlanning ? "Testing" : "ReviewPlan";
    54→      console.error("[app] navigating to:", nextScreen);
    55→      if (nextScreen === "Testing") {
    56→        setScreen(Screen.Testing({ plan: testPlan }));
    57→      } else {
    58→        setScreen(Screen.ReviewPlan({ plan: testPlan }));
    59→      }
    60→      console.error(
    61→        "[app] setScreen called, current screen._tag:",
    62→        useNavigationStore.getState().screen._tag,
    63→      );
    64→    } catch (error) {
    65→      console.error("[app] planning failed:", String(error));
    66→      setPlanningError(String(error));
    67→    }
    68→  };
    69→
    70→  const goBack = () => {
    71→    const { skipPlanning } = usePreferencesStore.getState();
    72→
    73→    if (screen._tag === "ReviewPlan" || screen._tag === "Planning") {
    74→      setPlanningError(undefined);
    75→      setScreen(Screen.Main());
    76→      return;
    77→    }
    78→    if (screen._tag === "CookieSyncConfirm") {
    79→      if (skipPlanning) {
    80→        setScreen(Screen.Main());
    81→      } else {
    82→        setScreen(Screen.ReviewPlan({ plan: screen.plan }));
    83→      }
    84→      return;
    85→    }
    86→    if (screen._tag === "Results") {
    87→      usePlanStore.getState().setPlan(undefined);
    88→      usePlanExecutionStore.getState().setExecutedPlan(undefined);
    89→      setScreen(Screen.Main());
    90→      return;
    91→    }
    92→    if (screen._tag !== "Testing") {
    93→      setScreen(Screen.Main());
    94→    }
    95→  };
    96→
    97→  const [, setRefreshTick] = useState(0);
    98→  const [, rows] = useStdoutDimensions();
    99→
   100→  useInput((input, key) => {
   101→    if (key.ctrl && input === "l") {
   102→      clearInkDisplay();
   103→      setRefreshTick((previous) => previous + 1);
   104→      return;
   105→    }
   106→    if (key.escape && screen._tag !== "Main" && screen._tag !== "ReviewPlan") {
   107→      goBack();
   108→    }
   109→    if (key.ctrl && input === "p" && screen._tag === "Main" && gitState?.isGitRepo) {
   110→      navigateTo(Screen.SelectPr());
   111→    }
   112→    if (key.ctrl && input === "t") {
   113→      navigateTo(Screen.Theme());
   114→    }
   115→  });
   116→
   117→  if (gitStateLoading || !gitState) {
   118→    return (
   119→      <Box flexDirection="column" paddingX={2} paddingY={1}>
   120→        <Spinner message="Checking git state..." />
   121→      </Box>
   122→    );
   123→  }
   124→
   125→  if (screen._tag === "Planning" && !planningError) {
   126→    void handlePlanningStart();
   127→  }
   128→
   129→  const renderScreen = () => {
   130→    switch (screen._tag) {
   131→      case "Testing":
   132→        return <TestingScreen plan={screen.plan} />;
   133→      case "Results":
   134→        return <ResultsScreen report={screen.report} />;
   135→      case "Theme":
   136→        return <ThemePickerScreen />;
   137→      case "SelectPr":
   138→        return <PrPickerScreen />;
   139→      case "Planning":
   140→        return (
   141→          <Box flexDirection="column" width="100%">
   142→            <PlanningScreen instruction={screen.instruction} />
   143→            {planningError ? (
   144→              <Box flexDirection="column" paddingX={2}>
   145→                <Text color={COLORS.RED}>Planning failed: {planningError}</Text>
   146→                <Text color={COLORS.DIM}>Press esc to go back.</Text>
   147→              </Box>
   148→            ) : null}
   149→          </Box>
   150→        );
   151→      case "ReviewPlan":
   152→        return <PlanReviewScreen plan={screen.plan} />;
   153→      case "CookieSyncConfirm":
   154→        return <CookieSyncConfirmScreen plan={screen.plan} />;
   155→      default:
   156→        return <MainMenu gitState={gitState} />;
   157→    }
   158→  };
   159→
   160→  return (
   161→    <MouseProvider>
   162→      <Box flexDirection="column" width="100%" height={rows}>
   163→        <Box flexGrow={1}>{renderScreen()}</Box>
   164→        <Modeline />
   165→      </Box>
   166→    </MouseProvider>
   167→  );
   168→};
